**代码：**

```c++
//
// Created by Cosmos on 2020/7/26.
//
#include <iostream>
#include <string.h>
#include <vector>
#include <map>
#include <queue>
#include <cmath>
#include <algorithm>
#include <unordered_map>
#include <numeric>
using namespace std;

class Solution {
public:
    map<string, int> res;
    void dfs(const string &formula, const int &multiple) {
        int len = formula.length();
        int cur = 0;
        while (cur < len) {
            if(formula[cur] >= 'A' && formula[cur] <= 'Z') {
                string curAtom;
                curAtom.push_back(formula[cur]);
                ++cur;
                while (formula[cur] >= 'a' && formula[cur] <= 'z') {
                    curAtom.push_back(formula[cur]);
                    ++cur;
                }
                if(formula[cur] >= '0' && formula[cur] <= '9') {
                    int num = 0;
                    while (formula[cur] >= '0' && formula[cur] <= '9') {
                        num = (num << 3) + (num << 1) + (formula[cur] - '0');
                        ++cur;
                    }
                    res[curAtom] += num * multiple;
                }
                else
                    res[curAtom] += multiple;
            }
            else if(formula[cur] == '(') {
                int count = 1;
                for(int i = cur + 1; i < len; ++i) {
                    if(formula[i] == '(')
                        ++count;
                    else if(formula[i] == ')')
                        --count;
                    if(count == 0) {
                        string newFormula = formula.substr(cur + 1, i - (cur + 1));
                        ++i;
                        if(formula[i] >= '0' && formula[i] <= '9') {
                            int newCount = 0;
                            while (formula[i] >= '0' && formula[i] <= '9') {
                                newCount = (newCount << 3) + (newCount << 1) + (formula[i] - '0');
                                ++i;
                            }
                            dfs(newFormula, multiple * newCount);
                        }
                        else {
                            dfs(newFormula, multiple);
                        }
                        cur = i;
                        break;
                    }
                }
            }
        }
    }
    string countOfAtoms(string formula) {
        dfs(formula, 1);
        string ans;
        for(auto it = res.begin(); it != res.end(); ++it) {
            ans += it->first;
            if(it->second == 1)
                continue;
            ans += to_string(it->second);
        }
        return ans;
    }
};

int main() {
    string input;
    cin >> input;
    string res = Solution().countOfAtoms(input);
    cout << res << endl;
    return 0;
}
```
